query ($startDate: Date!, $endDate: Date!, $limit: Int, $offset: Int) {
  account {
    id
    ...UsersReport
  }
}

fragment UsersReport on Account {
  users(limit: $limit, offset: $offset) {
    id
    email
    firstName
    lastName
    registrationDate
    firstLogin
    lastLogin
    lastActive 
    assessmentPassedCount(startDate: $startDate, endDate: $endDate)
    assessmentFailedCount(startDate: $startDate, endDate: $endDate)
    certificatesEarnedCount(startDate: $startDate, endDate: $endDate)
    itemViewCount(startDate: $startDate, endDate: $endDate)
    presentationsViewCount(startDate: $startDate, endDate: $endDate)
    language
    timeZone
    stateCode
    countryCode
    groups {
      name
    }
    customAnswers {
      questionText
      answerText
    }
  }
}

query ($startDate: Date!, $endDate: Date!, $limit: Int, $offset: Int, $withArchived: Boolean, $subLimit: Int, $subOffset: Int) {
  account {
    id
    ...CoursesReport
  }
}

fragment CoursesReport on Account {
  courses(limit: $limit, offset: $offset, withArchived: $withArchived) {
    name
      createdAt
      userVisitsCount(startDate: $startDate, endDate: $endDate)
      courseUserVisitsDetail(subLimit: $subLimit, subOffset: $subOffset) {
        stateCode
        email
        firstName
        lastName
        registrationDate
        lastLogin
        courseItemViewsCount(startDate: $startDate, endDate: $endDate)
        courseProgressCompletion
      }
      courseItemViewCount
      courseItemViews(startDate: $startDate, endDate: $endDate) {
        name
        type
        createdAt
        userVisitsCount
        credits {
          type
          value
        }
      }
      status
      averageRating
      ratingsCount
  }
}

